class DSU(val n: Long) {
    private val parent: LongArray
    private val rank: LongArray

    init {
        parent = LongArray(n.toInt() + 1) { it.toLong() }
        rank = LongArray(n.toInt() + 1) { 0L }
    }

    fun find(x: Long): Long {
        if (parent[x.toInt()] != x) {
            parent[x.toInt()] = find(parent[x.toInt()])
        }
        return parent[x.toInt()]
    }

    fun union(x: Long, y: Long): Boolean {
        val xRoot = find(x)
        val yRoot = find(y)
        if (xRoot == yRoot) return false
        if (rank[xRoot.toInt()] < rank[yRoot.toInt()]) {
            parent[xRoot.toInt()] = yRoot
        } else {
            parent[yRoot.toInt()] = xRoot
            if (rank[xRoot.toInt()] == rank[yRoot.toInt()]) {
                rank[xRoot.toInt()]++
            }
        }
        return true
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    edges.sortBy { it[2] }
    val maxWeight = edges.lastOrNull()?.get(2) ?: 0L
    var low = 0L
    var high = maxWeight
    var answer = high

    while (low <= high) {
        val mid = (low + high) / 2
        val dsu = DSU(n)
        for (edge in edges) {
            if (edge[2] <= mid) {
                dsu.union(edge[0], edge[1])
            }
        }
        val roots = mutableSetOf<Long>()
        for (i in 0 until n.toInt()) {
            roots.add(dsu.find(i.toLong()))
        }
        val m = roots.size
        if (m <= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
}
